import{_ as e,p as a,q as s,a1 as n}from"./framework-5866ffd3.js";const i={},d=n(`<h1 id="echo" tabindex="-1"><a class="header-anchor" href="#echo" aria-hidden="true">#</a> echo</h1><p>输出指定的字符串或者变量</p><h2 id="补充说明" tabindex="-1"><a class="header-anchor" href="#补充说明" aria-hidden="true">#</a> 补充说明</h2><p><strong>echo命令</strong> 用于在shell中打印shell变量的值，或者直接输出指定的字符串。linux的echo命令，在shell编程中极为常用, 在终端下打印变量value的时候也是常常用到的，因此有必要了解下echo的用法echo命令的功能是在显示器上显示一段文字，一般起到一个提示的作用。</p><h3 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>echo<span class="token punctuation">(</span>选项<span class="token punctuation">)</span><span class="token punctuation">(</span>参数<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="选项" tabindex="-1"><a class="header-anchor" href="#选项" aria-hidden="true">#</a> 选项</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>-e：激活转义字符。
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>使用<code>-e</code>选项时，若字符串中出现以下字符，则特别加以处理，而不会将它当成一般文字输出：</p><ul><li><code>\\a</code> 发出警告声；</li><li><code>\\b</code> 删除前一个字符；</li><li><code>\\c</code> 不产生进一步输出 (\\c 后面的字符不会输出)；</li><li><code>\\f</code> 换行但光标仍旧停留在原来的位置；</li><li><code>\\n</code> 换行且光标移至行首；</li><li><code>\\r</code> 光标移至行首，但不换行；</li><li><code>\\t</code> 插入tab；</li><li><code>\\v</code> 与\\f相同；</li><li><code>\\\\</code> 插入\\字符；</li><li><code>\\nnn</code> 插入 <code>nnn</code>（八进制）所代表的ASCII字符；</li></ul><h3 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h3><p>变量：指定要打印的变量。</p><h3 id="实例" tabindex="-1"><a class="header-anchor" href="#实例" aria-hidden="true">#</a> 实例</h3><p>用echo命令打印带有色彩的文字：</p><p><strong>文字色：</strong></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">echo</span> <span class="token parameter variable">-e</span> <span class="token string">&quot;<span class="token entity" title="\\e">\\e</span>[1;31mThis is red text<span class="token entity" title="\\e">\\e</span>[0m&quot;</span>
This is red text
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>\\e[1;31m</code> 将颜色设置为红色</li><li><code>\\e[0m</code> 将颜色重新置回</li></ul><p>颜色码：重置=0，黑色=30，红色=31，绿色=32，黄色=33，蓝色=34，洋红=35，青色=36，白色=37</p><p><strong>背景色</strong> ：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">echo</span> <span class="token parameter variable">-e</span> <span class="token string">&quot;<span class="token entity" title="\\e">\\e</span>[1;42mGreed Background<span class="token entity" title="\\e">\\e</span>[0m&quot;</span>
Greed Background
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>颜色码：重置=0，黑色=40，红色=41，绿色=42，黄色=43，蓝色=44，洋红=45，青色=46，白色=47</p><p><strong>文字闪动：</strong></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">echo</span> <span class="token parameter variable">-e</span> <span class="token string">&quot;<span class="token entity" title="\\033">\\033</span>[37;31;5mMySQL Server Stop...<span class="token entity" title="\\033">\\033</span>[39;49;0m&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>红色数字处还有其他数字参数：0 关闭所有属性、1 设置高亮度（加粗）、4 下划线、5 闪烁、7 反显、8 消隐</p>`,24),l=[d];function c(t,o){return a(),s("div",null,l)}const p=e(i,[["render",c],["__file","echo.html.vue"]]);export{p as default};
